--
-- Base de datos: `capa_inter`
--

DELIMITER $$
--
-- Procedimientos
--
CREATE DEFINER=`root`@`localhost` PROCEDURE `VerVentasYProductos` (IN `p_IDusuario` INT)   BEGIN
    -- Productos vendidos
    SELECT 
        p.IDproducto,
        p.Nombre AS NombreProducto,
        p.Precio,
        v.PrecioVenta,
        v.FechaVenta,
        u_comprador.NombreUsuario AS Comprador
    FROM ventas v
    JOIN productos p ON v.IDproducto = p.IDproducto
    JOIN usuario u_comprador ON v.IDcomprador = u_comprador.IDusuario
    WHERE p.IDusuario = p_IDusuario;

    -- Productos realizados (no vendidos)
    SELECT 
        p.IDproducto,
        p.Nombre AS NombreProducto,
        p.Precio,
        p.fecha_creacion
    FROM productos p
    WHERE p.IDusuario = p_IDusuario
    AND p.IDproducto NOT IN (SELECT IDproducto FROM ventas);
END$$

DELIMITER ;

